  const upper = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === upper)
}

/**
 * Calculates the Haversine great-circle distance (in kilometres) between
 * two points given as latitude/longitude strings.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const toRad = (deg: number): number => (deg * Math.PI) / 180
  const R = 6371 // Earth's mean radius in km

  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const Δφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const Δλ = toRad(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}

